    "\n"
    "<script>\n"
    "const HOST = location.hostname === 'localhost' ? '192.168.4.1' : location.hostname;\n"
    "const BASE = `http://${HOST}`;\n"
    "\n"
    "let sensors = [];\n"
    "let activeSensor = null;\n"
    "let eventSource = null;\n"
    "let graphValues = [];\n"
    "const GRAPH_MAX = 80;\n"
    "\n"
    "// ── Init ──────────────────────────────────────────────────────────────────\n"
    "\n"
    "async function init() {\n"
    "  await loadBoards();\n"
    "  await loadSensors();\n"
    "  await loadConfig();\n"
    "  setStatus(true);\n"
    "  document.getElementById('fw-ver').textContent = 'v1.0.0';\n"
    "}\n"
    "\n"
    "function setStatus(ok) {\n"
    "  const dot = document.getElementById('status-dot');\n"
    "  dot.className = ok ? 'ok' : 'err';\n"
    "}\n"
    "\n"
    "// ── Board ─────────────────────────────────────────────────────────────────\n"
    "\n"
    "async function loadBoards() {\n"
    "  const r = await fetch(`${BASE}/api/grove/boards`).catch(() => null);\n"
    "  if (!r) return;\n"
    "  const data = await r.json();\n"
    "  const sel = document.getElementById('board-select');\n"
    "  sel.innerHTML = '';\n"
    "  for (const b of data.boards) {\n"
    "    const o = document.createElement('option');\n"
    "    o.value = b.id; o.textContent = b.name;\n"
    "    o.dataset.d = b.d; o.dataset.d2 = b.d2;\n"
    "    sel.appendChild(o);\n"
    "  }\n"
    "  sel.addEventListener('change', onBoardChange);\n"
    "  updatePinInfo(sel.selectedOptions[0]);\n"
    "}\n"
    "\n"
    "async function onBoardChange() {\n"
    "  const sel = document.getElementById('board-select');\n"
    "  const opt = sel.selectedOptions[0];\n"
    "  await fetch(`${BASE}/api/grove/board`, {\n"
    "    method: 'POST',\n"
    "    headers: {'Content-Type':'application/json'},\n"
    "    body: JSON.stringify({board: opt.value})\n"
    "  });\n"
    "  updatePinInfo(opt);\n"
    "  if (activeSensor) showWiring(activeSensor, opt.dataset.d, opt.dataset.d2);\n"
    "}\n"
    "\n"
    "function updatePinInfo(opt) {\n"
    "  document.getElementById('pin-info').innerHTML =\n"
    "    `D: <span>GPIO${opt.dataset.d}</span> &nbsp; D2: <span>GPIO${opt.dataset.d2}</span>`;\n"
    "}\n"
    "\n"
    "// ── Sensors ───────────────────────────────────────────────────────────────\n"
    "\n"
    "async function loadSensors() {\n"
    "  const r = await fetch(`${BASE}/api/grove/sensors`).catch(() => null);\n"
    "  if (!r) return;\n"
    "  const data = await r.json();\n"
    "  sensors = data.sensors;\n"
    "  renderSensorGrid();\n"
    "}\n"
    "\n"
    "function renderSensorGrid() {\n"
    "  const grid = document.getElementById('sensor-grid');\n"
    "  grid.innerHTML = '';\n"
    "  for (const s of sensors) {\n"
    "    const btn = document.createElement('button');\n"
    "    btn.className = 'sensor-btn';\n"
    "    btn.innerHTML = `\n"
    "      <span class=\"sname\">${s.name}</span>\n"
    "      <span class=\"scat\">${s.category}</span>\n"
    "      <span class=\"svcc ${s.gpio_safe ? 'safe-ok' : 'safe-warn'}\">\n"
    "        ${s.gpio_safe ? '✓' : '⚠'} ${s.vcc}\n"
    "      </span>`;\n"
    "    btn.addEventListener('click', () => selectSensor(s));\n"
    "    btn.dataset.id = s.id;\n"
    "    grid.appendChild(btn);\n"
    "  }\n"
    "}\n"
    "\n"
    "async function selectSensor(s) {\n"
    "  stopStream();\n"
    "  activeSensor = s;\n"
    "\n"
    "  // Highlight\n"
    "  document.querySelectorAll('.sensor-btn').forEach(b =>\n"
    "    b.classList.toggle('active', b.dataset.id === s.id));\n"
    "\n"
    "  showVoltageBanner(s);\n"
    "\n"
    "  const sel = document.getElementById('board-select');\n"
    "  const opt = sel.selectedOptions[0];\n"
    "  showWiring(s, opt.dataset.d, opt.dataset.d2);\n"
    "\n"
    "  // Configure on device\n"
    "  const r = await fetch(`${BASE}/api/grove/configure`, {\n"
    "    method: 'POST',\n"
    "    headers: {'Content-Type':'application/json'},\n"
    "    body: JSON.stringify({sensor: s.id, stream_interval_ms: getInterval()})\n"
    "  }).catch(() => null);\n"
    "  if (!r || !r.ok) { setStatus(false); return; }\n"
    "\n"
    "  showControls(s);\n"
    "  clearReading();\n"
    "  graphValues = [];\n"
    "  drawGraph();\n"
    "}\n"
    "\n"
    "// ── Voltage Banner ────────────────────────────────────────────────────────\n"
    "\n"
    "function showVoltageBanner(s) {\n"
    "  const banner = document.getElementById('voltage-banner');\n"
    "  const badge  = document.getElementById('banner-badge');\n"
    "  const title  = document.getElementById('banner-title-text');\n"
    "  const body   = document.getElementById('banner-body');\n"
    "\n"
    "  banner.style.display = 'block';\n"
    "  if (s.gpio_safe) {\n"
    "    banner.className = 'safe';\n"
    "    badge.className  = 'badge-safe';\n"
    "    badge.textContent = '3.3V SAFE';\n"
    "    title.textContent = s.name;\n"
    "  } else {\n"
    "    banner.className = 'caution';\n"
    "    badge.className  = 'badge-caution';\n"
    "    badge.textContent = '⚠ VOLTAGE WARNING';\n"
    "    title.textContent = s.name;\n"
    "  }\n"
    "  body.textContent = s.voltage_note;\n"
    "}\n"
    "\n"
    "// ── Pin Wiring Diagram ────────────────────────────────────────────────────\n"
    "\n"
    "function showWiring(s, d, d2) {\n"
    "  const card = document.getElementById('wiring-card');\n"
    "  const diag = document.getElementById('pin-diagram');\n"
    "  card.style.display = 'block';\n"
    "  diag.style.display = 'block';\n"
    "\n"
    "  const vccColor = s.gpio_safe ? '#3fb950' : '#f85149';\n"
    "  const vccNote  = s.gpio_safe ? '3.3V' : '5V (⚠ external supply — NOT ESP32 3.3V pin if sensor draws >100mA)';\n"
    "\n"
    "  let lines = `\n"
    "<span class=\"pin-vcc\">● VCC  → ${vccNote}</span>\n"
    "<span class=\"pin-gnd\">● GND  → GND</span>\n"
    "<span class=\"pin-d\" >● ${s.d_role.padEnd(5)} → GPIO${d}  (D)</span>`;\n"
    "  if (s.uses_d2) {\n"
    "    lines += `\\n<span class=\"pin-d2\">● ${(s.d2_role||'D2').padEnd(5)} → GPIO${d2} (D2)</span>`;\n"
    "  }\n"
    "  diag.innerHTML = lines;\n"
    "}\n"
    "\n"
    "// ── Controls ──────────────────────────────────────────────────────────────\n"
    "\n"
    "function showControls(s) {\n"
    "  document.getElementById('controls-card').style.display = 'block';\n"
    "  document.getElementById('reading-card').style.display  = 'block';\n"
    "  document.getElementById('graph-card').style.display    = 'block';\n"
    "\n"
    "  const isOutput = s.id === 'digital_out' || s.id === 'pwm_out';\n"
    "  const isRotary = s.id === 'rotary';\n"
    "\n"
    "  document.getElementById('controls').style.display        = isOutput ? 'none' : 'flex';\n"
    "  document.getElementById('output-controls').style.display = isOutput ? 'flex' : 'none';\n"
    "  document.getElementById('btn-rotary-reset').style.display = isRotary ? 'inline-block' : 'none';\n"
    "\n"
    "  if (s.id === 'pwm_out') {\n"
    "    document.getElementById('out-value').max = 255;\n"
    "    document.getElementById('out-value').placeholder = 'duty 0–255';\n"
    "  } else if (s.id === 'digital_out') {\n"
    "    document.getElementById('out-value').max = 1;\n"
    "    document.getElementById('out-value').placeholder = '0 or 1';\n"
    "  }\n"
    "}\n"
    "\n"
    "function getInterval() {\n"
    "  return parseInt(document.getElementById('interval-slider').value, 10);\n"
    "}\n"
    "\n"
    "document.getElementById('interval-slider').addEventListener('input', function() {\n"
    "  document.getElementById('interval-val').textContent = this.value;\n"
    "});\n"
    "\n"
    "document.getElementById('btn-start').addEventListener('click', startStream);\n"
    "document.getElementById('btn-stop').addEventListener('click', stopStream);\n"
    "document.getElementById('btn-once').addEventListener('click', readOnce);\n"
    "document.getElementById('btn-write').addEventListener('click', writeOutput);\n"
    "document.getElementById('btn-rotary-reset').addEventListener('click', resetRotary);\n"
    "\n"
    "// ── Stream ────────────────────────────────────────────────────────────────\n"
    "\n"
    "function startStream() {\n"
    "  if (eventSource) stopStream();\n"
    "  eventSource = new EventSource(`${BASE}/api/grove/stream`);\n"
    "  eventSource.addEventListener('reading', e => displayReading(JSON.parse(e.data)));\n"
    "  eventSource.addEventListener('error', () => setStatus(false));\n"
    "  document.getElementById('btn-start').style.display = 'none';\n"
    "  document.getElementById('btn-stop').style.display  = 'inline-block';\n"
    "}\n"
    "\n"
    "function stopStream() {\n"
    "  if (eventSource) { eventSource.close(); eventSource = null; }\n"
    "  document.getElementById('btn-start').style.display = 'inline-block';\n"
    "  document.getElementById('btn-stop').style.display  = 'none';\n"
    "}\n"
    "\n"
    "async function readOnce() {\n"
    "  const r = await fetch(`${BASE}/api/grove/read`).catch(() => null);\n"
    "  if (!r) { setStatus(false); return; }\n"
    "  displayReading(await r.json());\n"
    "}\n"
    "\n"
    "// ── Output ────────────────────────────────────────────────────────────────\n"
    "\n"
    "async function writeOutput() {\n"
    "  if (!activeSensor) return;\n"
    "  const val = parseInt(document.getElementById('out-value').value, 10);\n"
    "  const body = activeSensor.id === 'pwm_out' ? {duty: val} : {value: val};\n"
    "  await fetch(`${BASE}/api/grove/write`, {\n"
    "    method: 'POST', headers: {'Content-Type':'application/json'},\n"
    "    body: JSON.stringify(body)\n"
    "  });\n"
    "}\n"
    "\n"
    "async function resetRotary() {\n"
    "  await fetch(`${BASE}/api/grove/rotary/reset`, {method:'POST'});\n"
    "}\n"
    "\n"
    "// ── Display Reading ───────────────────────────────────────────────────────\n"
    "\n"
    "function displayReading(data) {\n"
    "  setStatus(true);\n"
    "  const display = document.getElementById('reading-display');\n"
    "  const errEl   = document.getElementById('error-msg');\n"
    "  display.style.display = 'block';\n"
    "\n"
    "  if (data.error) {\n"
    "    errEl.textContent = '⚠ ' + data.error;\n"
    "    errEl.style.display = 'block';\n"
    "    display.innerHTML = '';\n"
    "    return;\n"
    "  }\n"
    "  errEl.style.display = 'none';\n"
    "\n"
    "  const rows = [];\n"
    "  let graphVal = null;\n"
    "\n"
    "  if ('value' in data)       { rows.push(['Signal', data.value, data.label || '']); graphVal = data.value; }\n"
    "  if ('raw' in data)         { rows.push(['Raw (ADC)', data.raw, '']); graphVal = data.raw; }\n"
    "  if ('voltage' in data && 'raw' in data) rows.push(['Voltage', data.voltage, 'V']);\n"
    "  if ('temperature' in data) { rows.push(['Temperature', data.temperature, '°C']); graphVal = parseFloat(data.temperature); }\n"
    "  if ('humidity' in data)    rows.push(['Humidity', data.humidity, '%RH']);\n"
    "  if ('distance_cm' in data) { rows.push(['Distance', data.distance_cm, 'cm']); graphVal = parseFloat(data.distance_cm); }\n"
    "  if ('steps' in data)       { rows.push(['Steps', data.steps, '']); graphVal = data.steps; }\n"
    "  if ('duty' in data)        rows.push(['PWM Duty', data.duty, '/ 255']);\n"
    "\n"
    "  display.innerHTML = rows.map(([lbl, val, unit]) =>\n"
    "    `<div class=\"reading-row\">\n"
    "       <span class=\"reading-label\">${lbl}</span>\n"
    "       <span><span class=\"reading-value\">${val}</span><span class=\"reading-unit\">${unit}</span></span>\n"
    "     </div>`\n"
    "  ).join('');\n"
    "\n"
    "  document.getElementById('reading-ts').textContent =\n"
    "    `Updated ${new Date().toLocaleTimeString()}`;\n"
    "\n"
    "  if (graphVal !== null && isFinite(graphVal)) {\n"
    "    graphValues.push(graphVal);\n"
    "    if (graphValues.length > GRAPH_MAX) graphValues.shift();\n"
    "    drawGraph();\n"
    "  }\n"
    "}\n"
    "\n"
    "function clearReading() {\n"
    "  document.getElementById('reading-display').innerHTML = '';\n"
    "  document.getElementById('error-msg').style.display = 'none';\n"
    "}\n"
    "\n"
    "// ── Graph ─────────────────────────────────────────────────────────────────\n"
    "\n"
    "function drawGraph() {\n"
    "  const canvas = document.getElementById('graph');\n"
    "  const ctx = canvas.getContext('2d');\n"
    "  canvas.width  = canvas.offsetWidth  * devicePixelRatio;\n"
    "  canvas.height = canvas.offsetHeight * devicePixelRatio;\n"
    "  ctx.scale(devicePixelRatio, devicePixelRatio);\n"
    "  const W = canvas.offsetWidth, H = canvas.offsetHeight;\n"
    "  const pad = 8;\n"
    "\n"
    "  ctx.clearRect(0, 0, W, H);\n"
    "  if (graphValues.length < 2) return;\n"
    "\n"
    "  const min = Math.min(...graphValues);\n"
    "  const max = Math.max(...graphValues);\n"
    "  const range = max - min || 1;\n"
    "\n"
    "  // Grid\n"
    "  ctx.strokeStyle = '#30363d'; ctx.lineWidth = 1;\n"
    "  for (let i = 0; i <= 4; i++) {\n"
    "    const y = pad + (H - pad*2) * (1 - i/4);\n"
    "    ctx.beginPath(); ctx.moveTo(pad, y); ctx.lineTo(W - pad, y); ctx.stroke();\n"
    "  }\n"
    "\n"
    "  // Line\n"
    "  ctx.strokeStyle = '#58a6ff'; ctx.lineWidth = 2;\n"
    "  ctx.beginPath();\n"
    "  graphValues.forEach((v, i) => {\n"
    "    const x = pad + (W - pad*2) * i / (GRAPH_MAX - 1);\n"
    "    const y = pad + (H - pad*2) * (1 - (v - min) / range);\n"
    "    i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);\n"
    "  });\n"
    "  ctx.stroke();\n"
    "\n"
    "  // Labels\n"
    "  ctx.fillStyle = '#8b949e'; ctx.font = `${10 * devicePixelRatio / devicePixelRatio}px monospace`;\n"
    "  ctx.fillText(max.toFixed(1), pad + 2, pad + 10);\n"
    "  ctx.fillText(min.toFixed(1), pad + 2, H - pad - 2);\n"
    "}\n"
    "\n"
    "window.addEventListener('resize', drawGraph);\n"
    "\n"
    "// ── Load existing config ──────────────────────────────────────────────────\n"
    "\n"
    "async function loadConfig() {\n"
    "  const r = await fetch(`${BASE}/api/grove/config`).catch(() => null);\n"
    "  if (!r) return;\n"
    "  const cfg = await r.json();\n"
    "  const sel = document.getElementById('board-select');\n"
    "  for (const opt of sel.options) {\n"
    "    if (opt.value === cfg.board) { sel.value = opt.value; updatePinInfo(opt); break; }\n"
    "  }\n"
    "  if (cfg.sensor) {\n"
    "    const s = sensors.find(x => x.id === cfg.sensor);\n"
    "    if (s) {\n"
    "      document.querySelectorAll('.sensor-btn').forEach(b =>\n"
    "        b.classList.toggle('active', b.dataset.id === s.id));\n"
    "      activeSensor = s;\n"
    "      showVoltageBanner(s);\n"
    "      const opt = sel.selectedOptions[0];\n"
    "      showWiring(s, opt.dataset.d, opt.dataset.d2);\n"
    "      showControls(s);\n"
    "    }\n"
    "  }\n"
    "}\n"
    "\n"
    "init().catch(console.error);\n"
    "</script>\n"
    "</body>\n"
    "</html>\n"
    "";

void setupWebApp() {
    apiServer.http().on("/", HTTP_GET, [](AsyncWebServerRequest* req) {
        AsyncWebServerResponse* resp = req->beginResponse_P(200, "text/html", INDEX_HTML);
        resp->addHeader("Cache-Control", "no-cache");
        req->send(resp);
    });
    Serial.println("[API] Web app registered at /");
}
